Below is a refactor that keeps the behavior essentially the same, but makes it:

- easier to read
- easier to test
- safer to change
- easier to extend with new modes/output formats

I’ll first show the refactored code, then explain every design decision in detail.

---

## Refactored code

```python
from __future__ import annotations

from dataclasses import dataclass
from enum import Enum
import json
from typing import Any, Iterable


class ProcessingMode(str, Enum):
    FAST = "fast"
    CAREFUL = "careful"


class OutputType(str, Enum):
    JSON = "json"
    CSV = "csv"
    RAW = "raw"


@dataclass(frozen=True)
class ProcessOptions:
    mode: ProcessingMode
    flag1: bool = False
    flag2: bool = True
    output_type: OutputType = OutputType.JSON


@dataclass(frozen=True)
class Result:
    id: Any
    val: float
    status: str

    def to_dict(self) -> dict[str, Any]:
        return {"id": self.id, "val": self.val, "status": self.status}


def process(
    data: Iterable[dict[str, Any]],
    mode: str,
    flag1: bool = False,
    flag2: bool = True,
    output_type: str = "json",
) -> str | list[dict[str, Any]]:
    """
    Backward-compatible wrapper around the refactored implementation.
    """
    options = ProcessOptions(
        mode=ProcessingMode(mode),
        flag1=flag1,
        flag2=flag2,
        output_type=_parse_output_type(output_type),
    )
    return DataProcessor(options).process(data)


class DataProcessor:
    def __init__(self, options: ProcessOptions) -> None:
        self.options = options

    def process(self, data: Iterable[dict[str, Any]]) -> str | list[dict[str, Any]]:
        results = [result.to_dict() for result in self._process_items(data)]
        return self._format_output(results)

    def _process_items(self, data: Iterable[dict[str, Any]]) -> list[Result]:
        if self.options.mode == ProcessingMode.FAST:
            return self._process_fast(data)
        if self.options.mode == ProcessingMode.CAREFUL:
            return self._process_careful(data)
        raise ValueError(f"Unsupported processing mode: {self.options.mode}")

    def _process_fast(self, data: Iterable[dict[str, Any]]) -> list[Result]:
        results: list[Result] = []

        for item in data:
            item_type = item.get("type")

            if item_type == "A":
                result = self._process_fast_type_a(item)
                if result is not None:
                    results.append(result)

            elif item_type == "B":
                results.append(self._process_fast_type_b(item))

            else:
                result = self._process_fast_unknown_type(item)
                if result is not None:
                    results.append(result)

        return results

    def _process_fast_type_a(self, item: dict[str, Any]) -> Result:
        value = item["value"]
        adjusted_value = value * 1.1 if self.options.flag1 else value

        if adjusted_value > 100:
            if self.options.flag2:
                return Result(id=item["id"], val=adjusted_value, status="high")
            return Result(id=item["id"], val=adjusted_value * 0.9, status="adjusted")

        return Result(id=item["id"], val=adjusted_value, status="normal")

    def _process_fast_type_b(self, item: dict[str, Any]) -> Result:
        discounted_value = item["value"] * 0.95
        return Result(id=item["id"], val=discounted_value, status="discounted")

    def _process_fast_unknown_type(self, item: dict[str, Any]) -> Result | None:
        if self.options.flag1 and self.options.flag2:
            return Result(id=item["id"], val=0, status="skip")
        return None

    def _process_careful(self, data: Iterable[dict[str, Any]]) -> list[Result]:
        results: list[Result] = []

        for item in data:
            results.append(self._process_careful_item(item))

        return results

    def _process_careful_item(self, item: dict[str, Any]) -> Result:
        try:
            value = float(item.get("value", 0))
            if value < 0:
                raise ValueError("negative")
            return Result(id=item["id"], val=value, status="validated")
        except (ValueError, TypeError, KeyError):
            return Result(id=item.get("id"), val=0, status="error")

    def _format_output(self, results: list[dict[str, Any]]) -> str | list[dict[str, Any]]:
        if self.options.output_type == OutputType.JSON:
            return json.dumps(results)

        if self.options.output_type == OutputType.CSV:
            return self._to_csv(results)

        if self.options.output_type == OutputType.RAW:
            return results

        raise ValueError(f"Unsupported output type: {self.options.output_type}")

    @staticmethod
    def _to_csv(results: list[dict[str, Any]]) -> str:
        return "\n".join(
            f"{result['id']},{result['val']},{result['status']}"
            for result in results
        )


def _parse_output_type(output_type: str) -> OutputType:
    if output_type == "json":
        return OutputType.JSON
    if output_type == "csv":
        return OutputType.CSV
    return OutputType.RAW
```

---

# Why this is better

---

## 1. The original code had too many responsibilities in one function

The original `process()` did all of this at once:

- interpreted options
- decided processing mode
- processed each item
- handled multiple item types
- encoded output to JSON/CSV/raw

That makes the function hard to reason about and hard to test. A single change could break unrelated behavior.

### Refactor decision
I split responsibilities into:

- `process(...)`: backward-compatible wrapper
- `DataProcessor`: orchestration
- `_process_fast(...)` and `_process_careful(...)`: mode-specific logic
- `_process_fast_type_a(...)`, `_process_fast_type_b(...)`, `_process_fast_unknown_type(...)`: item-type-specific logic
- `_format_output(...)`: output formatting
- `Result`: structured result object
- `ProcessOptions`: structured configuration object

This follows the **single responsibility principle**.

---

## 2. Replace “stringly typed” mode/output values with enums

In the original code:

```python
mode == 'fast'
output_type == 'json'
```

These are error-prone because typos are easy:

- `"fasst"`
- `"jsno"`

Those errors become runtime bugs and are hard to catch.

### Refactor decision
I introduced:

```python
class ProcessingMode(str, Enum):
    FAST = "fast"
    CAREFUL = "careful"
```

and

```python
class OutputType(str, Enum):
    JSON = "json"
    CSV = "csv"
    RAW = "raw"
```

### Why this helps
- makes valid values explicit
- improves autocomplete in IDEs
- centralizes supported options
- makes code easier to refactor safely

I still kept the public `process(...)` signature using strings so callers don’t break.

---

## 3. Group options into a dataclass

The original function took several parameters:

```python
def process(data, mode, flag1=False, flag2=True, output_type='json'):
```

This is manageable now, but it scales poorly as more flags get added.

### Refactor decision
I created:

```python
@dataclass(frozen=True)
class ProcessOptions:
    mode: ProcessingMode
    flag1: bool = False
    flag2: bool = True
    output_type: OutputType = OutputType.JSON
```

### Why this helps
- all config lives in one place
- easier to pass through the system
- easier to test combinations of options
- `frozen=True` makes it immutable, which reduces accidental mutation bugs

---

## 4. Introduce a result model instead of building dicts everywhere

Original code repeatedly did this:

```python
results.append({'id': item['id'], 'val': val, 'status': 'normal'})
```

This duplicates structure all over the code.

### Refactor decision
I created:

```python
@dataclass(frozen=True)
class Result:
    id: Any
    val: float
    status: str
```

with:

```python
def to_dict(self) -> dict[str, Any]:
    return {"id": self.id, "val": self.val, "status": self.status}
```

### Why this helps
- one clear definition of a result
- easier to validate and evolve
- less repeated dictionary construction
- more self-documenting than anonymous dict literals

---

## 5. Separate processing modes into dedicated methods

In the old code, this nested structure was hard to follow:

```python
for item in data:
    if mode == 'fast':
        ...
    elif mode == 'careful':
        ...
```

That means mode logic is mixed inside the loop and mixed with item-specific logic.

### Refactor decision
I moved mode dispatch out:

```python
def _process_items(self, data):
    if self.options.mode == ProcessingMode.FAST:
        return self._process_fast(data)
    if self.options.mode == ProcessingMode.CAREFUL:
        return self._process_care

# Refactored Code with Design Decisions

Here's the refactored version of the code with explanations for each design decision:

```python
import json
from abc import ABC, abstractmethod
from typing import List, Dict, Union, Optional

class DataProcessor(ABC):
    """Abstract base class for different processing strategies."""
    @abstractmethod
    def process_item(self, item: Dict) -> Dict:
        pass

class FastModeProcessor(DataProcessor):
    """Processor for 'fast' mode with specific business rules."""
    def __init__(self, flag1: bool = False, flag2: bool = True):
        self.flag1 = flag1
        self.flag2 = flag2

    def process_item(self, item: Dict) -> Dict:
        """Process individual item according to fast mode rules."""
        if item.get('type') == 'A':
            return self._process_type_a(item)
        elif item.get('type') == 'B':
            return self._process_type_b(item)
        else:
            return self._process_other_type(item)

    def _process_type_a(self, item: Dict) -> Dict:
        """Handle processing for type A items."""
        value = item['value'] * 1.1 if self.flag1 else item['value']

        if value > 100:
            if self.flag2:
                return {'id': item['id'], 'val': value, 'status': 'high'}
            else:
                return {'id': item['id'], 'val': value * 0.9, 'status': 'adjusted'}
        else:
            return {'id': item['id'], 'val': value, 'status': 'normal'}

    def _process_type_b(self, item: Dict) -> Dict:
        """Handle processing for type B items."""
        value = item['value'] * 0.95
        return {'id': item['id'], 'val': value, 'status': 'discounted'}

    def _process_other_type(self, item: Dict) -> Dict:
        """Handle processing for other item types."""
        if self.flag1 and self.flag2:
            return {'id': item['id'], 'val': 0, 'status': 'skip'}
        raise ValueError(f"Unprocessable item type: {item.get('type')}")

class CarefulModeProcessor(DataProcessor):
    """Processor for 'careful' mode with validation."""
    def process_item(self, item: Dict) -> Dict:
        """Process individual item with careful validation."""
        try:
            value = float(item.get('value', 0))
            if value < 0:
                raise ValueError('negative value')
            return {'id': item['id'], 'val': value, 'status': 'validated'}
        except (ValueError, TypeError):
            return {'id': item['id'], 'val': 0, 'status': 'error'}

class OutputFormatter(ABC):
    """Abstract base class for different output formats."""
    @abstractmethod
    def format(self, results: List[Dict]) -> Union[str, List[Dict]]:
        pass

class JsonFormatter(OutputFormatter):
    """Format results as JSON string."""
    def format(self, results: List[Dict]) -> str:
        return json.dumps(results)

class CsvFormatter(OutputFormatter):
    """Format results as CSV string."""
    def format(self, results: List[Dict]) -> str:
        return '\n'.join([f"{r['id']},{r['val']},{r['status']}" for r in results])

class ListFormatter(OutputFormatter):
    """Format results as raw list of dictionaries."""
    def format(self, results: List[Dict]) -> List[Dict]:
        return results

def get_processor(mode: str, flag1: bool, flag2: bool) -> DataProcessor:
    """Factory method to get the appropriate processor."""
    if mode == 'fast':
        return FastModeProcessor(flag1, flag2)
    elif mode == 'careful':
        return CarefulModeProcessor()
    else:
        raise ValueError(f"Unknown processing mode: {mode}")

def get_formatter(output_type: str) -> OutputFormatter:
    """Factory method to get the appropriate formatter."""
    if output_type == 'json':
        return JsonFormatter()
    elif output_type == 'csv':
        return CsvFormatter()
    else:
        return ListFormatter()

def process_data(
    data: List[Dict],
    mode: str = 'fast',
    flag1: bool = False,
    flag2: bool = True,
    output_type: str = 'json'
) -> Union[str, List[Dict]]:
    """
    Main processing function that orchestrates the workflow.

    Args:
        data: List of items to process
        mode: Processing mode ('fast' or 'careful')
        flag1: First processing flag (affects type A items)
        flag2: Second processing flag (affects high values in type A)
        output_type: Desired output format ('json', 'csv', or raw list)

    Returns:
        Processed results in requested format
    """
    # Input validation
    if not isinstance(data, list):
        raise TypeError("Data must be a list of dictionaries")

    # Get the appropriate processor and formatter
    processor = get_processor(mode, flag1, flag2)
    formatter = get_formatter(output_type)

    # Process each item
    results = [processor.process_item(item) for item in data]

    # Format and return results
    return formatter.format(results)
```

## Design Decisions Explained

1. **Strategy Pattern Implementation**:
   - Created abstract base classes (`DataProcessor`, `OutputFormatter`) to define interfaces
   - Implemented concrete strategies for different processing modes (`FastModeProcessor`, `CarefulModeProcessor`) and output formats
   - This makes it easy to add new processing modes or output formats without modifying existing code

2. **Single Responsibility Principle**:
   - Split the monolithic function into smaller, focused classes/methods
   - Each class handles one specific aspect (processing or formatting)
   - Each method does one specific thing (like processing a particular item type)

3. **Proper Type Hints**:
   - Added type annotations throughout the code
   - Makes the code more self-documenting and enables static type checking

4. **Input Validation**:
   - Added basic input validation at the entry point
   - Prevents processing of invalid data structures

5. **Error Handling**:
   - Made error handling more explicit (like in `CarefulModeProcessor`)
   - Added proper exception raising for invalid modes

6. **Factory Methods**:
   - Created `get_processor` and `get_formatter` factory methods
   - Centralizes the creation logic and makes it easier to modify

7. **Improved Readability**:
   - Broke down nested conditionals into separate methods
   - Used descriptive method names that explain what the code does
   - Added docstrings for all public methods

8. **Testability**:
   - Each component can be tested in isolation
   - Mocking is easier due to clear interfaces
   - Reduced side effects (pure functions where possible)

9. **Maintainability**:
   - Clear separation of concerns
   - Easier to modify one part without affecting others
   - New requirements can be implemented by adding new classes rather than modifying existing ones

10. **Output Formatting**:
    - Extracted formatting logic to separate classes
    - Made output format handling consistent and extensible

11. **Default Parameters**:
    - Kept the same default parameters as the original function for backward compatibility
    - Made them explicit in the docstring

This refactored version is:
- More maintainable (clear structure, separation of concerns)
- More testable (isolated components with clear interfaces)
- More extensible (easy to add new modes or formats)
- More robust (better error handling and input validation)
- More readable (clear method names and structure)

The tradeoff is slightly more code, but the benefits in maintainability and extensibility far outweigh this cost.

This refactor transforms the "spaghetti" code into a modular, object-oriented, and testable system. We will use the **Strategy Pattern** for processing logic and **Factory Pattern** for formatting.

### The Refactored Code

```python
import json
from abc import ABC, abstractmethod
from typing import List, Dict, Any, Union

# --- 1. Domain Models ---

class ProcessedItem:
    """Standardized output structure."""
    def __init__(self, id: str, val: float, status: str):
        self.id = id
        self.val = val
        self.status = status

    def to_dict(self):
        return {"id": self.id, "val": self.val, "status": self.status}

# --- 2. Processing Strategies ---

class ProcessingStrategy(ABC):
    @abstractmethod
    def process_item(self, item: Dict[str, Any]) -> Union[ProcessedItem, None]:
        pass

class FastStrategy(ProcessingStrategy):
    def __init__(self, apply_bonus: bool = False, enable_high_status: bool = True):
        self.apply_bonus = apply_bonus
        self.enable_high_status = enable_high_status

    def process_item(self, item: Dict[str, Any]) -> Union[ProcessedItem, None]:
        item_type = item.get('type')
        value = item.get('value', 0)

        if item_type == 'A':
            return self._handle_type_a(item['id'], value)
        if item_type == 'B':
            return ProcessedItem(item['id'], value * 0.95, 'discounted')
        if self.apply_bonus and self.enable_high_status:
            return ProcessedItem(item['id'], 0, 'skip')
        return None

    def _handle_type_a(self, item_id: str, value: float) -> ProcessedItem:
        val = value * 1.1 if self.apply_bonus else value
        if val > 100:
            if self.enable_high_status:
                return ProcessedItem(item_id, val, 'high')
            return ProcessedItem(item_id, val * 0.9, 'adjusted')
        return ProcessedItem(item_id, val, 'normal')

class CarefulStrategy(ProcessingStrategy):
    def process_item(self, item: Dict[str, Any]) -> ProcessedItem:
        try:
            val = float(item.get('value', 0))
            if val < 0:
                raise ValueError("Negative value")
            return ProcessedItem(item['id'], val, 'validated')
        except (ValueError, TypeError, KeyError):
            return ProcessedItem(item.get('id', 'unknown'), 0, 'error')

# --- 3. Formatters ---

class Formatter:
    @staticmethod
    def to_json(data: List[ProcessedItem]) -> str:
        return json.dumps([item.to_dict() for item in data])

    @staticmethod
    def to_csv(data: List[ProcessedItem]) -> str:
        lines = [f"{item.id},{item.val},{item.status}" for item in data]
        return "\n".join(lines)

# --- 4. Main Entry Point ---

def process_data(
    data: List[Dict], 
    mode: str, 
    flag1: bool = False, 
    flag2: bool = True, 
    output_type: str = 'json'
):
    # Select Strategy
    strategies = {
        'fast': FastStrategy(apply_bonus=flag1, enable_high_status=flag2),
        'careful': CarefulStrategy()
    }

    strategy = strategies.get(mode)
    if not strategy:
        raise ValueError(f"Unknown mode: {mode}")

    # Execute logic
    results = []
    for item in data:
        result = strategy.process_item(item)
        if result:
            results.append(result)

    # Format output
    if output_type == 'json':
        return Formatter.to_json(results)
    if output_type == 'csv':
        return Formatter.to_csv(results)
    return results
```

---

### Design Decisions & Explanations

#### 1. Strategy Pattern (Decoupling Logic)
*   **Problem:** The original code used nested `if/else` blocks to handle `mode`. Adding a third mode would make the function unreadable.
*   **Solution:** I created `ProcessingStrategy` classes. `FastStrategy` and `CarefulStrategy` encapsulate their own rules.
*   **Benefit:** You can test `FastStrategy` in isolation without worrying about the `careful` logic.

#### 2. Descriptive Naming (Replacing Flags)
*   **Problem:** `flag1` and `flag2` are "mystery booleans." A developer reading `process(d, 'fast', True, False)` has no idea what those booleans do.
*   **Solution:** I renamed them to `apply_bonus` and `enable_high_status` within the classes. This makes the business logic self-documenting.

#### 3. Data Normalization (The `ProcessedItem` class)
*   **Problem:** The original code returned dictionaries with inconsistent keys or structure depending on the path taken.
*   **Solution:** A simple class (or dataclass) ensures that every processed item has an `id`, `val`, and `status`. This prevents "KeyErrors" later in the pipeline.

#### 4. Separation of Concerns (Formatting vs. Logic)
*   **Problem:** The original function did three things: filtered data, calculated values, and formatted strings.
*   **Solution:** I moved JSON and CSV logic into a `Formatter` class. The core logic should only care about *calculating* data, not how it's *printed*.

#### 5. Error Handling
*   **Problem:** The original `careful` mode used a "bare except" (`except:`), which is dangerous because it catches system interrupts like `KeyboardInterrupt`. 
*   **Solution:** I specified explicit exceptions (`ValueError`, `TypeError`) and handled the "missing ID" edge case.

#### 6. Flatter Code (Guard Clauses)
*   **Problem:** The original code was 5 levels deep in indentation (Arrow Code).
*   **Solution:** By using a strategy class and returning early (`return None`), I reduced the indentation level, making the code significantly easier to scan visually.

### How to Test this Code
Because of this structure, you can now write clean unit tests:
```python
def test_fast_strategy_type_a_bonus():
    strat = FastStrategy(apply_bonus=True)
    item = {'id': '1', 'type': 'A', 'value': 10}
    result = strat.process_item(item)
    assert result.val == 11.0  # 10 * 1.1
    assert result.status == 'normal'
```

Of course. This is an excellent exercise. The original code is a classic example of a "God Function" that violates several key software design principles.

Here is a breakdown of the problems, followed by the refactored code and a detailed explanation of the design decisions.

### Problems with the Original Code

1.  **God Function:** The single `process` function does everything: data validation, business logic for two different modes, and output formatting. This makes it long, complex, and hard to understand.
2.  **High Cyclomatic Complexity:** The nested `if/elif/else` blocks and `try/except` create a complex control flow. There are many possible execution paths, making it difficult to test every scenario.
3.  **Hard to Test:** To test the business logic for `mode='fast'`, you must provide an `output_type` that returns a Python object (e.g., not 'json' or 'csv'), or you have to parse the output string. To test the output formatting, you need to run the entire processing logic again. These concerns are tightly coupled.
4.  **Violates Single Responsibility Principle (SRP):** The function has multiple reasons to change. If the business logic for 'fast' mode changes, the function changes. If the CSV output format changes, the function changes.
5.  **Hardcoded Dependencies:** The function directly imports `json` inside its body, making it less flexible and harder to mock in tests.
6.  **Inconsistent Data Structures:** The 'careful' mode catches a generic `except` and returns `0` for `val`, while the 'fast' mode never handles potential `KeyError` or `TypeError` if `item['value']` is missing or not a number. This can lead to unpredictable crashes.

---

### Refactored Code

The refactoring is guided by the **Strategy** and **Factory** design patterns, and the principles of **SRP** and **Dependency Injection**.

```python
import json
from abc import ABC, abstractmethod
from dataclasses import dataclass, asdict
from typing import List, Dict, Any, Union, Optional

# --- 1. Data Models ---
# Using a dataclass provides a clear, structured contract for our data.
# This improves type hinting and reduces the risk of typos in dictionary keys.
@dataclass
class ProcessedItem:
    id: str
    val: float
    status: str

# --- 2. Strategy Interface ---
# This abstract base class defines the contract for all processing strategies.
# Each strategy will implement its own version of the `process` method.
class ProcessingStrategy(ABC):
    @abstractmethod
    def process(self, item: Dict[str, Any]) -> Optional[ProcessedItem]:
        """Processes a single data item and returns a ProcessedItem or None."""
        pass

# --- 3. Concrete Strategy Implementations ---
# Each strategy is now a separate class, focused on one specific task.

class FastModeStrategy(ProcessingStrategy):
    def __init__(self, flag1: bool = False, flag2: bool = True):
        self.flag1 = flag1
        self.flag2 = flag2

    def process(self, item: Dict[str, Any]) -> Optional[ProcessedItem]:
        item_type = item.get('type')
        item_id = item.get('id')
        value = item.get('value')

        # Guard clause for missing or invalid data
        if item_id is None or value is None or not isinstance(value, (int, float)):
            return None

        val = float(value)

        if item_type == 'A':
            val = val * 1.1 if self.flag1 else val
            if val > 100:
                if self.flag2:
                    return ProcessedItem(id=item_id, val=val, status='high')
                else:
                    return ProcessedItem(id=item_id, val=val * 0.9, status='adjusted')
            else:
                return ProcessedItem(id=item_id, val=val, status='normal')

        elif item_type == 'B':
            val = val * 0.95
            return ProcessedItem(id=item_id, val=val, status='discounted')

        else:
            if self.flag1 and self.flag2:
                return ProcessedItem(id=item_id, val=0, status='skip')

        return None

class CarefulModeStrategy(ProcessingStrategy):
    def process(self, item: Dict[str, Any]) -> Optional[ProcessedItem]:
        item_id = item.get('id')
        raw_value = item.get('value')

        if item_id is None:
            return None

        try:
            val = float(raw_value)
            if val < 0:
                raise ValueError('Negative value')
            return ProcessedItem(id=item_id, val=val, status='validated')
        except (ValueError, TypeError, AttributeError):
            # Catches float conversion errors, NoneType, non-numeric strings
            return ProcessedItem(id=item_id, val=0, status='error')

# --- 4. Output Formatter Interface and Implementations ---
# This separates the logic of formatting the final output.

class OutputFormatter(ABC):
    @abstractmethod
    def format(self, data: List[ProcessedItem]) -> str:
        """Formats a list of ProcessedItems into a string."""
        pass

class JsonFormatter(OutputFormatter):
    def format(self, data: List[ProcessedItem]) -> str:
        # Convert dataclasses to dicts for JSON serialization
        data_as_dicts = [asdict(item) for item in data]
        return json.dumps(data_as_dicts)

class CsvFormatter(OutputFormatter):
    def format(self, data: List[ProcessedItem]) -> str:
        header = "id,val,status"
        rows = [f"{item.id},{item.val},{item.status}" for item in data]
        return "\n".join([header] + rows) if rows else ""

class RawFormatter(OutputFormatter):
    def format(self, data: List[ProcessedItem]) -> str:
        # For raw output, we just return the list of objects.
        # The type hint is str, but we can return the list as it will be
        # handled by the processor. A better design might use a union type.
        return data # type: ignore

# --- 5. Processor (Context) ---
# This class orchestrates the process. It uses a strategy for processing
# and a formatter for output.

class DataProcessor:
    def __init__(self, strategy: ProcessingStrategy, formatter: OutputFormatter):
        self.strategy = strategy
        self.formatter = formatter

    def process(self, data: List[Dict[str, Any]]) -> str:
        # 1. Process each item using the strategy.
        #    Filter out any None results (from invalid items).
        processed_items = [item for item in (self.strategy.process(d) for d in data) if item]

        # 2. Format the results using the formatter.
        return self.formatter.format(processed_items)

# --- 6. Factory for easy creation (The new public API) ---
# This provides a simple, clean way to create a fully configured processor,
# hiding the complexity of the underlying classes.

def create_processor(
    mode: str,
    flag1: bool = False,
    flag2: bool = True,
    output_type: str = 'json'
) -> DataProcessor:
    """
    Factory function to create a configured DataProcessor instance.

    Args:
        mode (str): The processing mode ('fast' or 'careful').
        flag1 (bool): Flag for fast mode.
        flag2 (bool): Flag for fast mode.
        output_type (str): Desired output format ('json', 'csv', 'raw').

    Returns:
        DataProcessor: An instance ready to process data.
    """
    # Select Strategy
    if mode == 'fast':
        strategy = FastModeStrategy(flag1=flag1, flag2=flag2)
    elif mode == 'careful':
        strategy = CarefulModeStrategy()
    else:
        raise ValueError(f"Unknown mode: {mode}")

    # Select Formatter
    if output_type == 'json':
        formatter = JsonFormatter()
    elif output_type == 'csv':
        formatter = CsvFormatter()
    elif output_type == 'raw':
        formatter = RawFormatter()
    else:
        raise ValueError(f"Unknown output_type: {output_type}")

    return DataProcessor(strategy, formatter)

